import asyncio
import json
import websockets

class Item:
    def __init__(self, id, name):
        self.id = id
        self.name = name
        self.owner_id = None

class Player:
    def __init__(self, player_id):
        self.player_id = player_id
        self.inventory = []

    def add_item(self, item):
        self.inventory.append(item)

    def remove_item(self, item):
        if item in self.inventory:
            self.inventory.remove(item)
            return True
        return False

class GameServer:
    def __init__(self):
        self.players = {}
        self.items = {}

    async def register_player(self, player_id):
        if player_id not in self.players:
            self.players[player_id] = Player(player_id)

    async def add_item_to_server(self, item_id, item_name):
        if item_id not in self.items:
            self.items[item_id] = Item(item_id, item_name)

    async def handle_message(self, websocket, path):
        async for message in websocket:
            data = json.loads(message)
            action = data.get('action')
            player_id = data.get('player_id')
            item_id = data.get('item_id')

            await self.register_player(player_id)

            if action == 'add_item':
                item_name = data.get('item_name')
                await self.add_item_to_server(item_id, item_name)
                self.items[item_id].owner_id = player_id
                self.players[player_id].add_item(self.items[item_id])
                response = {'status': 'success', 'message': f'Item {item_id} added to your inventory'}
            elif action == 'trade_item':
                target_player_id = data.get('target_player_id')
                if item_id in self.items and self.items[item_id].owner_id == player_id:
                    await self.register_player(target_player_id)
                    current_owner = self.players[player_id]
                    new_owner = self.players[target_player_id]

                    current_owner.remove_item(self.items[item_id])
                    new_owner.add_item(self.items[item_id])
                    self.items[item_id].owner_id = target_player_id

                    response = {'status': 'success', 'message': f'Item {item_id} traded to player {target_player_id}'}
                else:
                    response = {'status': 'error', 'message': 'Invalid item or ownership'}
            else:
                response = {'status': 'error', 'message': 'Unknown action'}

            await websocket.send(json.dumps(response))

start_server = websockets.serve(GameServer().handle_message, "localhost", 8765)

asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()